int main() {
    // Create a SportsCar object polymorphically via a Vehicle pointer
    Vehicle* myVehicle = new SportsCar();
    myVehicle->startEngine(); // Call base method

    // To call derived methods, we need to cast to the appropriate type
    Car* myCar = static_cast<Car*>(myVehicle);
    myCar->drive();

    SportsCar* mySportsCar = static_cast<SportsCar*>(myVehicle);
    mySportsCar->activateBoost();

    // Polymorphic deletion: `virtual ~Vehicle()` ensures all destructors are called in reverse order
    delete myVehicle;
    return 0;
}
